SELECT model_name
FROM vehicles
ORDER BY model_name ASC;

SELECT COUNT(user_id) AS user_count, permission
FROM user_permissions
GROUP BY permission;

SELECT DISTINCT manufacturer
FROM vehicles
ORDER BY manufacturer ASC;

SELECT manufacturer, COUNT(vehicle_id) AS num_vehicles
FROM vehicles
GROUP BY manufacturer;

SELECT COUNT(*) AS total_toyota_vehicles
FROM vehicles
WHERE manufacturer = 'Toyota';

SELECT v.model_name, v.model_year, v.manufacturer
FROM vehicles v
WHERE EXISTS (SELECT 1 FROM trim_levels tl WHERE tl.vehicle_id = v.vehicle_id);
